import React, { useState } from "react";
import API from "../api/api";

/**
 * Insights Component
 * Features:
 * - AI-based player insights
 * - Input search
 * - Loading + error handling
 * - Clean result rendering
 */

function Insights() {
  const [query, setQuery] = useState("");
  const [result, setResult] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  /**
   * Fetch AI insights from backend
   */
  const fetchInsights = async () => {
    if (!query.trim()) return;

    setLoading(true);
    setError("");
    setResult("");

    try {
      const res = await API.post("/insights", {
        query: query
      });

      /**
       * Expected response:
       * { data: "AI generated insight..." }
       */
      if (res.data && res.data.data) {
        setResult(res.data.data);
      } else {
        setResult("No insights available");
      }
    } catch (err) {
      console.error("Insights error:", err);

      setError(
        err?.response?.data?.detail ||
        "Failed to fetch insights"
      );
    }

    setLoading(false);
  };

  /**
   * Handle Enter key
   */
  const handleKeyDown = (e) => {
    if (e.key === "Enter") {
      fetchInsights();
    }
  };

  return (
    <div className="container">
      <h2>📊 AI Cricket Insights</h2>

      <div className="card">
        <input
          type="text"
          placeholder="Ask something (e.g. Virat Kohli performance analysis)"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          onKeyDown={handleKeyDown}
          style={{ width: "100%", padding: "10px", marginBottom: "10px" }}
        />

        <button onClick={fetchInsights} disabled={loading}>
          {loading ? "Analyzing..." : "Get Insights"}
        </button>
      </div>

      {/* Loading */}
      {loading && (
        <div className="card">
          <p>⏳ Generating AI insights...</p>
        </div>
      )}

      {/* Error */}
      {error && (
        <div className="card">
          <p className="error">{error}</p>
        </div>
      )}

      {/* Result */}
      {result && (
        <div className="card">
          <h3>🧠 Insight Result</h3>
          <p style={{ lineHeight: "1.6" }}>{result}</p>
        </div>
      )}

      {/* Empty State */}
      {!loading && !result && !error && (
        <div className="card">
          <p>Try searching for player insights, match analysis, or predictions.</p>
        </div>
      )}
    </div>
  );
}

export default Insights;
